import math

class User:
    def __init__(self, id, tier):
        self.id = id
        self.tier = tier

class CartItem:
    def __init__(self, product_id, price, quantity):
        self.product_id = product_id
        self.price = price
        self.quantity = quantity

def validate_cart_items(cart):
    valid_products = [1, 2, 3]  # list of allowed products
    for item in cart:
        if item.product_id not in valid_products:
            return False
    return True

def apply_discount_code(cart, code, user):
    discount_codes = {
        "ADMIN_10%": {"code": "ADMIN_10%", "discount": 0.1, "tier": ["admin"]},
        "VIP_20%": {"code": "VIP_20%", "discount": 0.2, "tier": ["vip"]}
    }
    if code in discount_codes:
        for dc in discount_codes[code]:
            if dc["tier"] == user.tier or dc["tier"] == ["admin"]:
                cart.total *= (1 - dc["discount"])
                return cart
    return None

def calculate_tax(cart):
    tax_rate = 0.08  # 8% tax rate
    cart.tax = cart.subtotal * tax_rate
    return cart

def process_payment(cart, user):
    if cart.status != "paid":
        print("Payment processing failed.")
        return False
    return True

def create_order_record(cart, user):
    order_id = f"ORDER_{user.id}_{cart.id}"
    print(f"Order created: {order_id}")
    return True

class Cart:
    def __init__(self):
        self.items = []
        self.total = 0
        self.subtotal = 0
        self.tax = 0
        self.status = "pending"

def checkout(cart, code=None, user=User(None, None)):
    if not validate_cart_items(cart.items):
        print("Invalid cart items.")
        return False

    if code and apply_discount_code(cart, code, user) is None:
        print("Invalid discount code.")

    cart.subtotal = sum(item.price * item.quantity for item in cart.items)
    cart.total = cart.subtotal + cart.tax
    cart.status = "paid"

    if process_payment(cart, user):
        create_order_record(cart, user)
        return True

    return False

